import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface ParseError { readonly _tag: "ParseError"; readonly reason: string }
interface AgeError { readonly _tag: "AgeError"; readonly age: number }
type AppError = ParseError | AgeError;

interface User { readonly name: string; readonly age: number }

const parse = (raw: unknown): E.Either<ParseError, { name: string; age: number }> =>
  typeof raw === "object" && raw !== null && "name" in raw && "age" in raw
    ? E.right(raw as { name: string; age: number })
    : E.left({ _tag: "ParseError", reason: "missing fields" });

const checkAge = (u: { name: string; age: number }): E.Either<AgeError, User> =>
  u.age >= 18 ? E.right(u) : E.left({ _tag: "AgeError", age: u.age });

export const register = (raw: unknown): string =>
  pipe(
    parse(raw),
    E.chainW(checkAge),
    E.mapLeft((e): AppError => e),
    E.fold(
      (err) => `rejected: ${err._tag}`,
      (u) => `ok: ${u.name}`
    )
  );
