import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

const parseInt = (s: string): E.Either<"NaN", number> => {
  const n = Number(s);
  return Number.isFinite(n) ? E.right(n) : E.left("NaN");
};

const positive = (n: number): E.Either<"Negative", number> =>
  n >= 0 ? E.right(n) : E.left("Negative");

export const run = (s: string): string =>
  pipe(
    parseInt(s),
    E.chainW(positive),
    E.match(
      (err) => `bad: ${err}`,
      (n) => `ok: ${n}`
    )
  );
```

E.chainW widens the left channel to the union `"NaN" | "Negative"`, while plain E.chain would reject the second validator's error type.

E.chain requires the left type to be invariant across the pipeline — every step must fail with the same error. E.chainW (the widening variant) unifies different left types into a union, which is what you want when each step has its own tagged error. The final fold collapses both branches to one return type.

