import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface EmptyErr { readonly _tag: "Empty" }
interface TooLongErr { readonly _tag: "TooLong"; readonly length: number }
interface ForbiddenErr { readonly _tag: "Forbidden"; readonly word: string }

const nonEmpty = (s: string): E.Either<EmptyErr, string> =>
  s.length > 0 ? E.right(s) : E.left({ _tag: "Empty" });

const bounded = (s: string): E.Either<TooLongErr, string> =>
  s.length <= 80 ? E.right(s) : E.left({ _tag: "TooLong", length: s.length });

const clean = (s: string): E.Either<ForbiddenErr, string> =>
  !s.includes("badword") ? E.right(s) : E.left({ _tag: "Forbidden", word: "badword" });

export const sanitize = (s: string): string =>
  pipe(
    nonEmpty(s),
    E.chainW(bounded),
    E.chainW(clean),
    E.fold((e) => `rejected:${e._tag}`, (ok) => ok)
  );
