export const tryBoth = (s: string): E.Either<FinalErr, unknown> =>
  pipe(
    parseJson(s),
    E.orElseW((jsonErr) =>
      pipe(
        parseCsv(s),
        E.mapLeft((csvErr): FinalErr => ({ _tag: "BothFailed", json: jsonErr, csv: csvErr }))
      )
    )
  );

