  TE.tryCatch(
    async () => {
      const res = await fetch(url);
      if (!res.ok) throw new FetchError(`status ${res.status}`);
      return await res.text();
    },
    toFetchError
  );

export const fetchDescribed = (url: string) =>
  pipe(
    fetchText(url),
    TE.map((body) => body.slice(0, 100))
  );
