const timeoutTask = (ms: number): TE.TaskEither<TimeoutError, never> =>
  () =>
    new Promise((resolve) =>
      setTimeout(() => resolve(E.left({ _tag: "Timeout", ms })), ms)
    );

const race = <E1, E2, A>(
  a: TE.TaskEither<E1, A>,
  b: TE.TaskEither<E2, A>
): TE.TaskEither<E1 | E2, A> =>
  () => Promise.race([a(), b()]);

