import { Effect, Console } from "effect";

interface Conn { readonly id: string }

const acquire: Effect.Effect<Conn> = Effect.succeed({ id: "conn-1" });
const release = (c: Conn): Effect.Effect<void> =>
  Console.log(`released ${c.id}`);

