Wrap the release thunk in `Effect.catchAll` so its failure is swallowed and never masks the primary error channel.

```typescript
import { Effect, Console } from "effect";

declare const acquire: Effect.Effect<{ id: string }, Error>;
declare const use: (r: { id: string }) => Effect.Effect<void, Error>;
declare const rawRelease: (r: { id: string }) => Promise<void>;

const release = (r: { id: string }): Effect.Effect<void> =>
  Effect.tryPromise({ try: () => rawRelease(r), catch: (u) => u }).pipe(
    Effect.catchAll((u) =>
      Console.error(`release failed for ${r.id}: ${String(u)}`)
    )
  );

export const program: Effect.Effect<void, Error> = Effect.scoped(
  Effect.gen(function* () {
    const r = yield* Effect.acquireRelease(acquire, release);
    yield* use(r);
  })
);
```

```typescript
import { Effect, Ref } from "effect";

export const program: Effect.Effect<number> = Effect.gen(function* () {
  const counter = yield* Ref.make(0);
  const increments = Array.from({ length: 100 }, (_, i) => i);
  yield* Effect.forEach(
    increments,
    () => Ref.update(counter, (n) => n + 1),
    { concurrency: "unbounded", discard: true }
  );
  return yield* Ref.get(counter);
});
```

Ref.update reads, transforms, and writes atomically, so the 100 parallel fibres end up with exactly 100 in the counter — no lost updates.

```typescript
import { Effect, Ref } from "effect";

export const demo: Effect.Effect<number> = Effect.gen(function* () {
  const ref = yield* Ref.make(10);
  yield* Ref.update(ref, (n) => n + 1);
  yield* Ref.update(ref, (n) => n * 2);
  return yield* Ref.get(ref);
});
```

Ref is purely functional mutable state: every update returns a new `Effect<void>` that commits atomically. Multiple fibres can share the same ref safely.

Ref is implemented on top of a single atomic reference cell. `Ref.update(ref, f)` reads the current value, applies `f` purely, and writes the result in one atomic step — there is no gap during which another fibre could observe a stale value, so concurrent updates commute and compose. Reads via `Ref.get` never block and always see the most recent committed value.

```typescript
import { Effect, Ref } from "effect";

interface Stats { readonly hits: number; readonly misses: number }

export const track = Effect.gen(function* () {
  const ref = yield* Ref.make<Stats>({ hits: 0, misses: 0 });
  const events: ReadonlyArray<"hit" | "miss"> = ["hit", "miss", "hit", "hit"];

  yield* Effect.forEach(
    events,
    (ev) =>
      Ref.update(ref, (s) =>
        ev === "hit"
          ? { hits: s.hits + 1, misses: s.misses }
          : { hits: s.hits, misses: s.misses + 1 }
      ),
    { concurrency: "unbounded", discard: true }
  );

  return yield* Ref.get(ref);
});
```

