```typescript
import { Effect, Ref } from "effect";

export const mkCounter = Effect.gen(function* () {
  const ref = yield* Ref.make(0);
  const inc = Ref.update(ref, (n) => n + 1);
  const read = Ref.get(ref);
  const reset: Effect.Effect<number> = Ref.getAndSet(ref, 0);
